package com.courtassistant.core.result

/**
 * Sealed class for representing operation results
 */
sealed class Result<out T> {
    /**
     * Represents a successful operation with data
     */
    data class Success<T>(val data: T) : Result<T>()

    /**
     * Represents a failed operation with error information
     */
    data class Error(val error: Throwable? = null, val message: String? = null) : Result<Nothing>()

    /**
     * Represents a loading state
     */
    object Loading : Result<Nothing>()

    /**
     * Checks if the result is successful
     */
    inline fun onSuccess(action: (T) -> Unit): Result<T> {
        if (this is Success) {
            action(data)
        }
        return this
    }

    /**
     * Checks if the result is an error
     */
    inline fun onError(action: (Throwable?, String?) -> Unit): Result<T> {
        if (this is Error) {
            action(error, message)
        }
        return this
    }

    /**
     * Transforms the result using the given function
     */
    inline fun <R> map(transform: (T) -> R): Result<R> {
        return when (this) {
            is Success -> Success(transform(data))
            is Error -> this
            is Loading -> Loading
        }
    }

    /**
     * Gets the data if the result is successful, otherwise returns null
     */
    fun getOrNull(): T? {
        return if (this is Success) data else null
    }

    /**
     * Gets the error if the result is an error, otherwise returns null
     */
    fun getErrorOrNull(): Throwable? {
        return if (this is Error) error else null
    }

    /**
     * Gets the error message if the result is an error, otherwise returns null
     */
    fun getErrorMessageOrNull(): String? {
        return if (this is Error) message else null
    }
}

package com.shanfuchun.courtassistant.core.result

/**
 * Sealed class representing the result of an operation
 */
sealed class Result<out T> {

    /**
     * Success result with data
     */
    data class Success<T>(val data: T) : Result<T>()

    /**
     * Error result with message and optional throwable
     */
    data class Error(val message: String, val throwable: Throwable? = null) : Result<Nothing>()

    /**
     * Loading state
     */
    object Loading : Result<Nothing>()
}

/**
 * Extension function to check if result is successful
 */
inline val Result<*>.isSuccess: Boolean
    get() = this is Result.Success

/**
 * Extension function to check if result is error
 */
inline val Result<*>.isError: Boolean
    get() = this is Result.Error

/**
 * Extension function to check if result is loading
 */
inline val Result<*>.isLoading: Boolean
    get() = this is Result.Loading

/**
 * Extension function to get success data safely
 */
inline val <T> Result<T>.data: T?
    get() = if (this is Result.Success) this.data else null

/**
 * Extension function to get error message safely
 */
inline val Result<*>.errorMessage: String?
    get() = if (this is Result.Error) this.message else null

/**
 * Map function to transform result data
 */
inline fun <T, R> Result<T>.map(transform: (T) -> R): Result<R> {
    return when (this) {
        is Result.Success -> Result.Success(transform(this.data))
        is Result.Error -> this
        Result.Loading -> Result.Loading
    }
}

/**
 * Flat map function to transform result data with nested result
 */
inline fun <T, R> Result<T>.flatMap(transform: (T) -> Result<R>): Result<R> {
    return when (this) {
        is Result.Success -> transform(this.data)
        is Result.Error -> this
        Result.Loading -> Result.Loading
    }
}

/**
 * Handle different result states
 */
inline fun <T> Result<T>.handle(
    onSuccess: (T) -> Unit,
    onError: (String) -> Unit,
    onLoading: (() -> Unit)? = null
) {
    when (this) {
        is Result.Success -> onSuccess(data)
        is Result.Error -> onError(message)
        Result.Loading -> onLoading?.invoke()
    }
}

package com.shanfuchun.courtassistant.core.result

/**
 * Data class representing a successful result
 * This is provided for convenience and extends the Result.Success class
 */
data class Success<T>(
    override val data: T
) : Result<T>(data) {

    constructor(data: T, message: String? = null) : this(data)

    override fun toString(): String {
        return "Success(data=$data)"
    }
}

package com.shanfuchun.courtassistant.core.result

/**
 * Data class representing an error result
 * This is provided for convenience and extends the Result.Error class
 */
data class Error(
    override val message: String,
    override val throwable: Throwable? = null
) : Result<Nothing>(message, throwable) {

    constructor(error: Throwable) : this(error.message ?: "Unknown error", error)

    constructor(message: String) : this(message, null)

    override fun toString(): String {
        return "Error(message='$message', throwable=$throwable)"
    }
}

/**
 * Extension function to create an error result
 */
fun <T> createErrorResult(message: String, throwable: Throwable? = null): Result<T> {
    return Error(message, throwable)
}

/**
 * Extension function to create an error result from throwable
 */
fun <T> createErrorResult(throwable: Throwable): Result<T> {
    return Error(throwable)
}

package com.shanfuchun.courtassistant.data.mapper

import com.shanfuchun.courtassistant.data.SmsRecord
import com.shanfuchun.courtassistant.data.Entities

/**
 * Mapper class for converting between Entity and Domain objects for SMS
 */
object SmsMapper {

    /**
     * Convert Entity to Domain
     */
    fun toDomain(entity: SmsRecord): com.shanfuchun.courtassistant.domain.model.Sms {
        return com.shanfuchun.courtassistant.domain.model.Sms(
            id = entity.id,
            sender = entity.sender,
            body = entity.body,
            receiveTime = entity.receiveTime,
            hasLink = entity.hasLink,
            parseStatus = entity.parseStatus,
            documentIds = entity.documentIds.split(",").filter { it.isNotBlank() },
            hasSummons = entity.hasSummons,
            courtName = entity.courtName,
            partyName = entity.partyName,
            createdAt = entity.receiveTime
        )
    }

    /**
     * Convert Domain to Entity
     */
    fun toDomain(entity: SmsRecord): com.shanfuchun.courtassistant.data.entities.SmsEntity {
        return com.shanfuchun.courtassistant.data.entities.SmsEntity(
            id = entity.id,
            sender = entity.sender,
            body = entity.body,
            receiveTime = entity.receiveTime,
            hasLink = entity.hasLink,
            parseStatus = entity.parseStatus,
            documentIds = entity.documentIds,
            hasSummons = entity.hasSummons,
            courtName = entity.courtName,
            partyName = entity.partyName
        )
    }

    /**
     * Convert Entity list to Domain list
     */
    fun toDomainList(entities: List<SmsRecord>): List<com.shanfuchun.courtassistant.domain.model.Sms> {
        return entities.map { toDomain(it) }
    }

    /**
     * Convert Domain to Entity for insertion/update
     */
    fun toEntity(domain: com.shanfuchun.courtassistant.domain.model.Sms): SmsRecord {
        return SmsRecord(
            id = domain.id,
            sender = domain.sender,
            body = domain.body,
            receiveTime = domain.receiveTime,
            hasLink = domain.hasLink,
            parseStatus = domain.parseStatus,
            documentIds = domain.documentIds.joinToString(","),
            hasSummons = domain.hasSummons,
            courtName = domain.courtName,
            partyName = domain.partyName
        )
    }
}

