import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.data.Entities

/**
 * Mapper class for converting between Entity and Domain objects for Documents
 */
object DocumentMapper {

    /**
     * Convert Entity to Domain
     */
    fun toDomain(entity: DocumentRecord): com.shanfuchun.courtassistant.domain.model.Document {
        return com.shanfuchun.courtassistant.domain.model.Document(
            id = entity.id,
            smsId = entity.smsId,
            fileName = entity.fileName,
            filePath = entity.filePath,
            fileSize = entity.fileSize,
            sourceUrl = entity.sourceUrl,
            downloadTime = entity.downloadTime,
            parseStatus = entity.parseStatus,
            calendarSynced = entity.calendarSynced,
            displayName = entity.displayName
        )
    }

    /**
     * Convert Entity to Domain (Entity version)
     */
    fun toDomain(entity: DocumentRecord): com.shanfuchun.courtassistant.data.entities.DocumentEntity {
        return com.shanfuchun.courtassistant.data.entities.DocumentEntity(
            id = entity.id,
            smsId = entity.smsId,
            fileName = entity.fileName,
            filePath = entity.filePath,
            fileSize = entity.fileSize,
            sourceUrl = entity.sourceUrl,
            downloadTime = entity.downloadTime,
            parseStatus = entity.parseStatus,
            calendarSynced = entity.calendarSynced,
            displayName = entity.displayName
        )
    }

    /**
     * Convert Entity list to Domain list
     */
    fun toDomainList(entities: List<DocumentRecord>): List<com.shanfuchun.courtassistant.domain.model.Document> {
        return entities.map { toDomain(it) }
    }

    /**
     * Convert Entity list to Entity list
     */
    fun toEntityList(entities: List<DocumentRecord>): List<com.shanfuchun.courtassistant.data.entities.DocumentEntity> {
        return entities.map { toDomain(it) }
    }

    /**
     * Convert Domain to Entity for insertion/update
     */
    fun toEntity(domain: com.shanfuchun.courtassistant.domain.model.Document): DocumentRecord {
        return DocumentRecord(
            id = domain.id,
            smsId = domain.smsId,
            fileName = domain.fileName,
            filePath = domain.filePath,
            fileSize = domain.fileSize,
            sourceUrl = domain.sourceUrl,
            downloadTime = domain.downloadTime,
            parseStatus = domain.parseStatus,
            calendarSynced = domain.calendarSynced,
            displayName = domain.displayName
        )
    }

    /**
     * Update entity from domain (preserving ID)
     */
    fun updateEntity(entity: DocumentRecord, domain: com.shanfuchun.courtassistant.domain.model.Document): DocumentRecord {
        return entity.copy(
            fileName = domain.fileName,
            filePath = domain.filePath,
            fileSize = domain.fileSize,
            sourceUrl = domain.sourceUrl,
            downloadTime = domain.downloadTime,
            parseStatus = domain.parseStatus,
            calendarSynced = domain.calendarSynced,
            displayName = domain.displayName
        )
    }
}

package com.shanfuchun.courtassistant.data.repository

import com.shanfuchun.courtassistant.data.daos.SmsDao
import com.shanfuchun.courtassistant.data.mapper.SmsMapper
import com.shanfuchun.courtassistant.data.SmsRecord
import com.shanfuchun.courtassistant.core.result.Result
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

/**
 * Repository for SMS operations using Repository Pattern
 */
class SmsRepository(
    private val smsDao: SmsDao
) {

    /**
     * Get all SMS records
     */
    suspend fun getAll(): Result<List<com.shanfuchun.courtassistant.domain.model.Sms>> {
        return try {
            Result.Success(SmsMapper.toDomainList(smsDao.getAllSync()))
        } catch (e: Exception) {
            Result.Error("Failed to get SMS records", e)
        }
    }

    /**
     * Get all SMS records as Flow
     */
    fun getAllFlow(): Flow<Result<List<com.shanfuchun.courtassistant.domain.model.Sms>>> {
        return smsDao.getAll().map { smsList ->
            try {
                Result.Success(SmsMapper.toDomainList(smsList))
            } catch (e: Exception) {
                Result.Error("Failed to get SMS records", e)
            }
        }
    }

    /**
     * Get SMS by ID
     */
    suspend fun getById(id: Long): Result<com.shanfuchun.courtassistant.domain.model.Sms?> {
        return try {
            val entity = smsDao.getById(id)
            Result.Success(entity?.let { SmsMapper.toDomain(it) })
        } catch (e: Exception) {
            Result.Error("Failed to get SMS by ID", e)
        }
    }

    /**
     * Search SMS by query
     */
    fun search(query: String): Flow<Result<List<com.shanfuchun.courtassistant.domain.model.Sms>>> {
        return smsDao.search(query).map { smsList ->
            try {
                Result.Success(SmsMapper.toDomainList(smsList))
            } catch (e: Exception) {
                Result.Error("Failed to search SMS", e)
            }
        }
    }

    /**
     * Insert new SMS record
     */
    suspend fun insert(sms: com.shanfuchun.courtassistant.domain.model.Sms): Result<Long> {
        return try {
            val entity = SmsMapper.toEntity(sms)
            val id = smsDao.insert(entity)
            Result.Success(id)
        } catch (e: Exception) {
            Result.Error("Failed to insert SMS", e)
        }
    }

    /**
     * Update SMS record
     */
    suspend fun update(sms: com.shanfuchun.courtassistant.domain.model.Sms): Result<Int> {
        return try {
            val entity = SmsMapper.toEntity(sms)
            Result.Success(smsDao.update(entity))
        } catch (e: Exception) {
            Result.Error("Failed to update SMS", e)
        }
    }

    /**
     * Get latest SMS receive time
     */
    suspend fun getLatestTime(): Result<Long?> {
        return try {
            Result.Success(smsDao.getLatestTime())
        } catch (e: Exception) {
            Result.Error("Failed to get latest SMS time", e)
        }
    }

    /**
     * Get SMS records by date range
     */
    suspend fun getByDateRange(startTime: Long, endTime: Long): Result<List<com.shanfuchun.courtassistant.domain.model.Sms>> {
        // This would need to be implemented in SmsDao if not already available
        return Result.Error("Not implemented yet")
    }

    /**
     * Get SMS records by court name
     */
    suspend fun getByCourtName(courtName: String): Result<List<com.shanfuchun.courtassistant.domain.model.Sms>> {
        // This would need to be implemented in SmsDao
        return Result.Error("Not implemented yet")
    }
}

