package com.shanfuchun.courtassistant.data.repository

import com.shanfuchun.courtassistant.data.daos.DocumentDao
import com.shanfuchun.courtassistant.data.mapper.DocumentMapper
import com.shanfuchun.courtassistant.data.DocumentRecord
import com.shanfuchun.courtassistant.core.result.Result
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

/**
 * Repository for Document operations using Repository Pattern
 */
class DocumentRepository(
    private val documentDao: DocumentDao
) {

    /**
     * Get all documents by SMS ID
     */
    fun getBySmsId(smsId: Long): Flow<Result<List<com.shanfuchun.courtassistant.domain.model.Document>>> {
        return documentDao.getBySmsId(smsId).map { documentList ->
            try {
                Result.Success(DocumentMapper.toDomainList(documentList))
            } catch (e: Exception) {
                Result.Error("Failed to get documents by SMS ID", e)
            }
        }
    }

    /**
     * Get all documents
     */
    suspend fun getAll(): Result<List<com.shanfuchun.courtassistant.domain.model.Document>> {
        return try {
            // This method would need to be added to DocumentDao
            Result.Error("Not implemented yet")
        } catch (e: Exception) {
            Result.Error("Failed to get all documents", e)
        }
    }

    /**
     * Get document by ID
     */
    suspend fun getById(id: Long): Result<com.shanfuchun.courtassistant.domain.model.Document?> {
        return try {
            val entity = documentDao.getById(id)
            Result.Success(entity?.let { DocumentMapper.toDomain(it) })
        } catch (e: Exception) {
            Result.Error("Failed to get document by ID", e)
        }
    }

    /**
     * Get documents by SMS ID (synchronous)
     */
    suspend fun getBySmsIdSync(smsId: Long): Result<List<com.shanfuchun.courtassistant.domain.model.Document>> {
        return try {
            val entities = documentDao.getBySmsIdSync(smsId)
            Result.Success(DocumentMapper.toDomainList(entities))
        } catch (e: Exception) {
            Result.Error("Failed to get documents by SMS ID", e)
        }
    }

    /**
     * Find document by URL and SMS ID
     */
    suspend fun findByUrlAndSms(url: String, smsId: Long): Result<com.shanfuchun.courtassistant.domain.model.Document?> {
        return try {
            val entity = documentDao.findByUrlAndSms(url, smsId)
            Result.Success(entity?.let { DocumentMapper.toDomain(it) })
        } catch (e: Exception) {
            Result.Error("Failed to find document by URL and SMS ID", e)
        }
    }

    /**
     * Find downloaded document by URL and SMS ID
     */
    suspend fun findDownloadedByUrlAndSms(url: String, smsId: Long): Result<com.shanfuchun.courtassistant.domain.model.Document?> {
        return try {
            val entity = documentDao.findDownloadedByUrlAndSms(url, smsId)
            Result.Success(entity?.let { DocumentMapper.toDomain(it) })
        } catch (e: Exception) {
            Result.Error("Failed to find downloaded document", e)
        }
    }

    /**
     * Insert new document
     */
    suspend fun insert(document: com.shanfuchun.courtassistant.domain.model.Document): Result<Long> {
        return try {
            val entity = DocumentMapper.toEntity(document)
            val id = documentDao.insert(entity)
            Result.Success(id)
        } catch (e: Exception) {
            Result.Error("Failed to insert document", e)
        }
    }

    /**
     * Update document
     */
    suspend fun update(document: com.shanfuchun.courtassistant.domain.model.Document): Result<Int> {
        return try {
            val entity = DocumentRecord(
                id = document.id,
                smsId = document.smsId,
                fileName = document.fileName,
                filePath = document.filePath,
                fileSize = document.fileSize,
                sourceUrl = document.sourceUrl,
                downloadTime = document.downloadTime,
                parseStatus = document.parseStatus,
                calendarSynced = document.calendarSynced,
                displayName = document.displayName
            )
            Result.Success(documentDao.update(entity))
        } catch (e: Exception) {
            Result.Error("Failed to update document", e)
        }
    }

    /**
     * Delete document
     */
    suspend fun delete(document: com.shanfuchun.courtassistant.domain.model.Document): Result<Int> {
        return try {
            val entity = DocumentMapper.toEntity(document)
            Result.Success(documentDao.delete(entity))
        } catch (e: Exception) {
            Result.Error("Failed to delete document", e)
        }
    }

    /**
     * Delete documents by IDs
     */
    suspend fun deleteByIds(ids: List<Long>): Result<Int> {
        return try {
            Result.Success(documentDao.deleteByIds(ids))
        } catch (e: Exception) {
            Result.Error("Failed to delete documents by IDs", e)
        }
    }

    /**
     * Get calendar synced count for SMS
     */
    suspend fun calendarSyncedCount(smsId: Long): Result<Int> {
        return try {
            Result.Success(documentDao.calendarSyncedCount(smsId))
        } catch (e: Exception) {
            Result.Error("Failed to get calendar synced count", e)
        }
    }

    /**
     * Get documents pending for webview processing
     */
    suspend fun getPendingWebviewDocs(): Result<List<com.shanfuchun.courtassistant.domain.model.Document>> {
        return try {
            val entities = documentDao.getPendingWebviewDocs()
            Result.Success(DocumentMapper.toDomainList(entities))
        } catch (e: Exception) {
            Result.Error("Failed to get pending webview documents", e)
        }
    }

    /**
     * Get documents stuck in processing
     */
    suspend fun getStuckProcessingDocs(threshold: Long = System.currentTimeMillis() - 300000): Result<List<com.shanfuchun.courtassistant.domain.model.Document>> {
        return try {
            val entities = documentDao.getStuckProcessingDocs(threshold)
            Result.Success(DocumentMapper.toDomainList(entities))
        } catch (e: Exception) {
            Result.Error("Failed to get stuck processing documents", e)
        }
    }

    /**
     * Check if document is processing
