package com.shanfuchun.courtassistant.data.daos

import androidx.lifecycle.LiveData
import androidx.room.*
import com.shanfuchun.courtassistant.data.SmsRecord

/**
 * Data Access Object for SMS operations
 */
@Dao
interface SmsDao {
    @Query("SELECT * FROM sms_record ORDER BY receiveTime DESC")
    fun getAll(): LiveData<List<SmsRecord>>

    @Query("SELECT * FROM sms_record ORDER BY receiveTime DESC")
    suspend fun getAllSync(): List<SmsRecord>

    @Query("SELECT * FROM sms_record WHERE body LIKE '%' || :q || '%' OR sender LIKE '%' || :q || '%' ORDER BY receiveTime DESC")
    fun search(q: String): LiveData<List<SmsRecord>>

    @Query("SELECT * FROM sms_record WHERE id = :id")
    suspend fun getById(id: Long): SmsRecord?

    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun insert(record: SmsRecord): Long

    @Update
    suspend fun update(record: SmsRecord)

    @Query("SELECT MAX(receiveTime) FROM sms_record")
    suspend fun getLatestTime(): Long?

    /**
     * Get SMS records by court name
     */
    @Query("SELECT * FROM sms_record WHERE courtName LIKE '%' || :courtName || '%' ORDER BY receiveTime DESC")
    suspend fun getByCourtName(courtName: String): List<SmsRecord>

    /**
     * Get SMS records by date range
     */
    @Query("SELECT * FROM sms_record WHERE receiveTime BETWEEN :startTime AND :endTime ORDER BY receiveTime DESC")
    suspend fun getByDateRange(startTime: Long, endTime: Long): List<SmsRecord>

    /**
     * Get SMS records by party name
     */
    @Query("SELECT * FROM sms_record WHERE partyName LIKE '%' || :partyName || '%' ORDER BY receiveTime DESC")
    suspend fun getByPartyName(partyName: String): List<SmsRecord>

    /**
     * Get SMS records by parse status
     */
    @Query("SELECT * FROM sms_record WHERE parseStatus = :status ORDER BY receiveTime DESC")
    suspend fun getByParseStatus(status: Int): List<SmsRecord>

    /**
     * Get SMS records with documents
     */
    @Query("SELECT * FROM sms_record WHERE documentIds IS NOT NULL AND documentIds != '' ORDER BY receiveTime DESC")
    suspend fun getWithDocuments(): List<SmsRecord>

    /**
     * Get SMS records with summons
     */
    @Query("SELECT * FROM sms_record WHERE hasSummons = 1 ORDER BY receiveTime DESC")
    suspend fun getWithSummons(): List<SmsRecord>

    /**
     * Update parse status
     */
    @Query("UPDATE sms_record SET parseStatus = :status WHERE id = :id")
    suspend fun updateParseStatus(id: Long, status: Int): Int

    /**
     * Update document IDs
     */
    @Query("UPDATE sms_record SET documentIds = :documentIds WHERE id = :id")
    suspend fun updateDocumentIds(id: Long, documentIds: String): Int

    /**
     * Count records by court name
     */
    @Query("SELECT COUNT(*) FROM sms_record WHERE courtName = :courtName")
    suspend fun countByCourtName(courtName: String): Int
}

package com.shanfuchun.courtassistant.data.daos

import androidx.lifecycle.LiveData
import androidx.room.*
import com.shanfuchun.courtassistant.data.DocumentRecord

/**
 * Data Access Object for Document operations
 */
@Dao
interface DocumentDao {
    @Query("SELECT * FROM document_record WHERE smsId = :smsId ORDER BY downloadTime DESC")
    fun getBySmsId(smsId: Long): LiveData<List<DocumentRecord>>

    @Query("SELECT * FROM document_record ORDER BY downloadTime DESC")
    fun getAll(): LiveData<List<DocumentRecord>>

    @Query("SELECT * FROM document_record WHERE id = :id")
    suspend fun getById(id: Long): DocumentRecord?

    @Query("SELECT * FROM document_record WHERE smsId = :smsId")
    suspend fun getBySmsIdSync(smsId: Long): List<DocumentRecord>

    @Query("SELECT * FROM document_record WHERE sourceUrl = :url AND smsId = :smsId LIMIT 1")
    suspend fun findByUrlAndSms(url: String, smsId: Long): DocumentRecord?

    @Query("SELECT * FROM document_record WHERE sourceUrl = :url AND smsId = :smsId AND parseStatus IN (0, 1, 2, 3, 5) LIMIT 1")
    suspend fun findDownloadedByUrlAndSms(url: String, smsId: Long): DocumentRecord?

    @Query("SELECT COUNT(*) FROM document_record WHERE smsId = :smsId AND calendarSynced = 1")
    suspend fun calendarSyncedCount(smsId: Long): Int

    @Insert
    suspend fun insert(record: DocumentRecord): Long

    @Update
    suspend fun update(record: DocumentRecord)

    @Delete
    suspend fun delete(record: DocumentRecord)

    @Query("DELETE FROM document_record WHERE id IN (:ids)")
    suspend fun deleteByIds(ids: List<Long>)

    @Query("SELECT * FROM document_record WHERE parseStatus = 4 ORDER BY downloadTime ASC")
    suspend fun getPendingWebviewDocs(): List<DocumentRecord>

    @Query("SELECT * FROM document_record WHERE parseStatus = 5 AND downloadTime < :threshold")
    suspend fun getStuckProcessingDocs(threshold: Long): List<DocumentRecord>

    @Query("SELECT COUNT(*) FROM document_record WHERE sourceUrl = :url AND smsId = :smsId AND parseStatus IN (4, 5)")
    suspend fun isProcessing(url: String, smsId: Long): Int

    /**
     * Get all documents (synchronous)
     */
    @Query("SELECT * FROM document_record ORDER BY downloadTime DESC")
    suspend fun getAllSync(): List<DocumentRecord>

    /**
     * Get documents by parse status
     */
    @Query("SELECT * FROM document_record WHERE parseStatus = :status ORDER BY downloadTime DESC")
    suspend fun getByParseStatus(status: Int): List<DocumentRecord>

    /**
     * Get documents by calendar sync status
     */
    @Query("SELECT * FROM document_record WHERE calendarSynced = :synced ORDER BY downloadTime DESC")
    suspend fun getByCalendarSynced(synced: Boolean): List<DocumentRecord>

    /**
     * Update parse status
     */
    @Query("UPDATE document_record SET parseStatus = :status WHERE id = :id")
    suspend fun updateParseStatus(id: Long, status: Int): Int

    /**
     * Update calendar sync status
     */
    @Query("UPDATE document_record SET calendarSynced = :synced WHERE id = :id")
    suspend fun updateCalendarSynced(id: Long, synced: Boolean): Int

    /**
     * Get documents by file name pattern
     */
    @Query("SELECT * FROM document_record WHERE fileName LIKE '%' || :pattern || '%' ORDER BY downloadTime DESC")
    suspend fun searchByFileName(pattern: String): List<DocumentRecord>

    /**
     * Count documents by SMS ID
     */
    @Query("SELECT COUNT(*) FROM document_record WHERE smsId = :smsId")
    suspend fun countBySmsId(smsId: Long): Int

    /**
     * Get documents older than specified time
     */
    @Query("SELECT * FROM document_record WHERE downloadTime < :time ORDER BY downloadTime ASC")
    suspend fun getOlderThan(time: Long): List<DocumentRecord>

    /**
     * Update display name
     */
    @Query("UPDATE document_record SET displayName = :name WHERE id = :id")
    suspend fun updateDisplayName(id: Long, name: String): Int
}

package com.shanfuchun.courtassistant.data.daos

import androidx.room.*
import com.shanfuchun.courtassistant.data.SummonsInfo

/**
 * Data Access Object for Summons operations
 */
@Dao
interface SummonsDao {
    @Query("SELECT * FROM summons_info WHERE documentId = :docId")
    suspend fun getByDocId(docId: Long): SummonsInfo?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(info: SummonsInfo): Long

    @Update
    suspend fun update(info: SummonsInfo): Int

    @Delete
    suspend fun delete(info: SummonsInfo): Int

    @Query("SELECT * FROM summons_info WHERE hearingTime > 0")
    suspend fun getAllWithHearing(): List<SummonsInfo>

    /**
     * Get summons by case number
     */
    @Query("SELECT * FROM summons_info WHERE caseNo = :caseNo")
    suspend fun getByCaseNumber(caseNo: String): List<SummonsInfo>

    /**
     * Get summons by court name
     */
    @Query("SELECT * FROM summons_info WHERE courtName LIKE '%' || :courtName || '%'")
    suspend fun getByCourtName(courtName: String): List<SummonsInfo>

    /**
     * Get summons by hearing date range
     */
    @Query("SELECT * FROM summons_info WHERE hearingTime BETWEEN :startTime AND :endTime")
    suspend fun getByHearingDateRange(startTime: Long, endTime: Long): List<SummonsInfo>

    /**
     * Get summons by party name
     */
    @Query("SELECT * FROM summons_info WHERE partyName LIKE '%' || :partyName || '%'")
    suspend fun getByPartyName(partyName: String): List<SummonsInfo>

    /**
     * Get summons by location
     */
    @Query("SELECT * FROM summons_info WHERE location LIKE '%' || :location || '%'")
    suspend fun getByLocation(location: String): List<SummonsInfo>

    /**
     * Get summons with confidence above threshold
     */
    @Query("SELECT * FROM summons_info WHERE confidence >= :minConfidence")
    suspend fun getByMinConfidence(minConfidence: Float): List<SummonsInfo>

    /**
     * Get summons by case type (derived from case number pattern)
     */
    @Query("SELECT * FROM summons_info WHERE caseNo LIKE :casePattern")
    suspend fun getByCaseType(casePattern: String): List<SummonsInfo>

    /**
     * Get upcoming summons (within next N days)
     */
    @Query("SELECT * FROM summons_info WHERE hearingTime BETWEEN :currentTime AND :endTime")
    suspend fun getUpcoming(currentTime: Long, endTime: Long): List<SummonsInfo>

    /**
     * Update hearing time
     */
    @Query("UPDATE summons_info SET hearingTime = :hearingTime WHERE id = :id")
    suspend fun updateHearingTime(id: Long, hearingTime: Long): Int

    /**
     * Update confidence
     */
    @Query("UPDATE summons_info SET confidence = :confidence WHERE id = :id")
    suspend fun updateConfidence(id: Long, confidence: Float): Int

    /**
     * Count summons by court name
     */
    @Query("SELECT COUNT(*) FROM summons_info WHERE courtName = :courtName")
    suspend fun countByCourtName(courtName: String): Int

    /**
     * Get summons with parsing status
     */
    @Query("SELECT * FROM summons_info WHERE hearingTime > 0 ORDER BY hearingTime ASC")
    suspend fun getWithParsingStatus(): List<SummonsInfo>

    /**
     * Delete summons by document ID
     */
    @Query("DELETE FROM summons_info WHERE documentId = :docId")
    suspend fun deleteByDocId(docId: Long): Int

    /**
     * Check if summons exists for case number
     */
    @Query("SELECT EXISTS(SELECT 1 FROM summons_info WHERE caseNo = :caseNo)")
    suspend fun existsByCaseNumber(caseNo: String): Boolean
}

