     */
    @Query("SELECT * FROM calendar_sync_record ORDER BY syncedAt DESC")
    suspend fun getAll(): List<CalendarSyncRecord>

    /**
     * Get calendar sync record by ID
     */
    @Query("SELECT * FROM calendar_sync_record WHERE id = :id")
    suspend fun getById(id: Long): CalendarSyncRecord?

    /**
     * Get calendar sync records by source ID
     */
    @Query("SELECT * FROM calendar_sync_record WHERE sourceId = :sourceId ORDER BY syncedAt DESC")
    suspend fun getBySourceId(sourceId: Long): List<CalendarSyncRecord>

    /**
     * Get calendar sync records by source type
     */
    @Query("SELECT * FROM calendar_sync_record WHERE sourceType = :sourceType ORDER BY syncedAt DESC")
    suspend fun getBySourceType(sourceType: String): List<CalendarSyncRecord>

    /**
     * Get calendar sync records by sync status
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = :status ORDER BY syncedAt DESC")
    suspend fun getBySyncStatus(status: Int): List<CalendarSyncRecord>

    /**
     * Get pending sync records (status = 0)
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = 0 ORDER BY syncedAt ASC")
    suspend fun getPendingSyncRecords(): List<CalendarSyncRecord>

    /**
     * Get synced records (status = 1)
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = 1 ORDER BY syncedAt DESC")
    suspend fun getSyncedRecords(): List<CalendarSyncRecord>

    /**
     * Get failed records (status = 2)
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncStatus = 2 ORDER BY syncedAt DESC")
    suspend fun getFailedRecords(): List<CalendarSyncRecord>

    /**
     * Get records by date range
     */
    @Query("SELECT * FROM calendar_sync_record WHERE syncedAt BETWEEN :startTime AND :endTime ORDER BY syncedAt DESC")
    suspend fun getByDateRange(startTime: Long, endTime: Long): List<CalendarSyncRecord>

    /**
     * Update sync status
     */
    @Query("UPDATE calendar_sync_record SET syncStatus = :status, syncedAt = :syncTime WHERE id = :id")
    suspend fun updateSyncStatus(id: Long, status: Int, syncTime: Long): Int

    /**
     * Update sync status without changing time
     */
    @Query("UPDATE calendar_sync_record SET syncStatus = :status WHERE id = :id")
    suspend fun updateSyncStatusOnly(id: Long, status: Int): Int

    /**
     * Update event ID
     */
    @Query("UPDATE calendar_sync_record SET eventId = :eventId WHERE id = :id")
    suspend fun updateEventId(id: Long, eventId: Long): Int

    /**
     * Delete calendar sync records by source ID
     */
    @Query("DELETE FROM calendar_sync_record WHERE sourceId = :sourceId")
    suspend fun deleteBySourceId(sourceId: Long): Int

    /**
     * Delete calendar sync records by source type
     */
    @Query("DELETE FROM calendar_sync_record WHERE sourceType = :sourceType")
    suspend fun deleteBySourceType(sourceType: String): Int

    /**
     * Delete old records (older than specified time)
     */
    @Query("DELETE FROM calendar_sync_record WHERE syncedAt < :time")
    suspend fun deleteOlderThan(time: Long): Int

    /**
     * Get records by dedup key pattern
     */
    @Query("SELECT * FROM calendar_sync_record WHERE dedupKey LIKE '%' || :pattern || '%'")
    suspend fun getByDedupKeyPattern(pattern: String): List<CalendarSyncRecord>

    /**
     * Count records by source type and status
     */
    @Query("SELECT COUNT(*) FROM calendar_sync_record WHERE sourceType = :sourceType AND syncStatus = :status")
    suspend fun countBySourceTypeAndStatus(sourceType: String, status: Int): Int

    /**
     * Get last sync time for source type
     */
    @Query("SELECT MAX(syncedAt) FROM calendar_sync_record WHERE sourceType = :sourceType AND syncStatus = 1")
    suspend fun getLastSyncTime(sourceType: String): Long?
}

package com.shanfuchun.courtassistant.data.mapper

import com.shanfuchun.courtassistant.data.SmsRecord

/**
 * Mapper class for converting between Entity and Domain objects for SMS
 */
object SmsMapper {

    /**
     * Convert Entity to Domain (for domain models)
     */
    fun toDomain(entity: SmsRecord): com.shanfuchun.courtassistant.domain.model.Sms {
        return com.shanfuchun.courtassistant.domain.model.Sms(
            id = entity.id,
            sender = entity.sender,
            body = entity.body,
            receiveTime = entity.receiveTime,
            hasLink = entity.hasLink,
            parseStatus = entity.parseStatus,
            documentIds = entity.documentIds.split(",").filter { it.isNotBlank() },
            hasSummons = entity.hasSummons,
            courtName = entity.courtName,
            partyName = entity.partyName,
            createdAt = entity.receiveTime
        )
    }

    /**
     * Convert Entity to Entity (for internal entity operations)
     */
    fun toEntity(domain: com.shanfuchun.courtassistant.domain.model.Sms): SmsRecord {
        return SmsRecord(
            id = domain.id,
            sender = domain.sender,
            body = domain.body,
            receiveTime = domain.receiveTime,
            hasLink = domain.hasLink,
            parseStatus = domain.parseStatus,
            documentIds = domain.documentIds.joinToString(","),
            hasSummons = domain.hasSummons,
            courtName = domain.courtName,
            partyName = domain.partyName
        )
    }

    /**
     * Convert Entity list to Domain list
     */
    fun toDomainList(entities: List<SmsRecord>): List<com.shanfuchun.courtassistant.domain.model.Sms> {
        return entities.map { toDomain(it) }
    }

    /**
     * Update existing entity from domain
     */
    fun updateEntity(entity: SmsRecord, domain: com.shanfuchun.courtassistant.domain.model.Sms): SmsRecord {
        return entity.copy(
            sender = domain.sender,
            body = domain.body,
            receiveTime = domain.receiveTime,
            hasLink = domain.hasLink,
            parseStatus = domain.parseStatus,
            documentIds = domain.documentIds.joinToString(","),
            hasSummons = domain.hasSummons,
            courtName = domain.courtName,
            partyName = domain.partyName
        )
    }
}

