package com.shanfuchun.courtassistant.data.repository

import com.shanfuchun.courtassistant.data.daos.*
import com.shanfuchun.courtassistant.data.mapper.*

/**
 * Repository Manager class that provides access to all repositories
 */
object RepositoryManager {

    // SMS Repository
    lateinit var smsRepository: SmsRepository
        private set

    // Document Repository
    lateinit var documentRepository: DocumentRepository
        private set

    // Summons Repository
    lateinit var summonsRepository: SummonsRepository
        private set

    // Calendar Sync Repository
    lateinit var calendarSyncRepository: CalendarSyncRepository
        private set

    /**
     * Initialize all repositories with their respective DAOs
     */
    fun initialize(
        smsDao: SmsDao,
        documentDao: DocumentDao,
        summonsDao: SummonsDao,
        calendarSyncDao: CalendarSyncDao
    ) {
        smsRepository = SmsRepository(smsDao)
        documentRepository = DocumentRepository(documentDao)
        summonsRepository = SummonsRepository(summonsDao)
        calendarSyncRepository = CalendarSyncRepository(calendarSyncDao)
    }

    /**
     * Get repository instance by type
     */
    fun <T> getRepository(type: RepositoryType): Any? {
        return when (type) {
            RepositoryType.SMS -> smsRepository
            RepositoryType.DOCUMENT -> documentRepository
            RepositoryType.SUMMONS -> summonsRepository
            RepositoryType.CALENDAR_SYNC -> calendarSyncRepository
        }
    }
}

/**
 * Enumeration of repository types
 */
enum class RepositoryType {
    SMS,
    DOCUMENT,
    SUMMONS,
    CALENDAR_SYNC
}

/**
 * Extension function to easily access repositories
 * Example: RepositoryManager.smsRepository.getAll()
 */

# Repository Pattern Usage Guide

## Overview

This guide explains how to use the newly implemented Repository Pattern in the Court Assistant application.

## Architecture

The data layer has been restructured with the following components:

1. **Core Layer** (`core/result/`)
   - `Result.kt` - Sealed class for operation results
   - `Success.kt` - Success result implementation
   - `Error.kt` - Error result implementation

2. **Data Layer** (`data/`)
   - `repository/` - Repository implementations
   - `daos/` - Individual DAO interfaces
   - `mapper/` - Entity to Domain model mappers
   - `entities/` - Room database entities

3. **Domain Layer** (`domain/model/`)
   - Domain models representing business objects

## Usage Examples

### 1. Using SMS Repository

```kotlin
// Get all SMS records
val smsResult = RepositoryManager.smsRepository.getAll()
smsResult.handle(
    onSuccess = { smsList ->
        // Handle successful result
        smsList.forEach { sms ->
            // Process SMS
        }
    },
    onError = { errorMessage ->
        // Handle error
        Log.e("SMSRepository", errorMessage)
    }
)

// Search SMS
RepositoryManager.smsRepository.search("court").collect { result ->
    when (result) {
        is Result.Success -> {
            // Handle search results
        }
        is Result.Error -> {
            // Handle search error
        }
    }
}

// Insert new SMS
val newSms = Sms(
    sender = "1234567890",
    body = "Court summons received",
    receiveTime = System.currentTimeMillis(),
    // ... other fields
)

RepositoryManager.smsRepository.insert(newSms).handle(
    onSuccess = { id ->
        Log.d("SMSRepository", "New SMS inserted with ID: $id")
    },
    onError = { error ->
        Log.e("SMSRepository", "Failed to insert SMS: $error")
    }
)
```

### 2. Using Document Repository

```kotlin
// Get documents by SMS ID
RepositoryManager.documentRepository.getBySmsId(smsId).collect { result ->
    when (result) {
        is Result.Success -> {
            val documents = result.data
            // Process documents
        }
        is Result.Error -> {
            // Handle error
        }
    }
}

// Insert new document
val newDocument = Document(
    smsId = 1,
    fileName = "summons.pdf",
    filePath = "/path/to/summons.pdf",
    sourceUrl = "https://example.com/summons.pdf",
    parseStatus = 0
)

RepositoryManager.documentRepository.insert(newDocument)
```

### 3. Using Result Handling

```kotlin
// Generic function to handle repository results
suspend fun <T> safeRepositoryCall(repositoryCall: suspend () -> Result<T>): T? {
    return try {
        val result = repositoryCall()
        when (result) {
            is Result.Success -> result.data
            is Result.Error -> {
                Log.e("Repository", "Error: ${result.message}")
                null
            }
            Result.Loading -> null
        }
    } catch (e: Exception) {
        Log.e("Repository", "Unexpected error", e)
        null
    }
}

// Usage example
val sms = safeRepositoryCall {
    RepositoryManager.smsRepository.getById(1)
}
```

### 4. Initialization

```kotlin
// In your Application or Database class
class App : Application() {
    override fun onCreate() {
        super.onCreate()

        // Initialize database
        val database = Room.databaseBuilder(
            applicationContext,
            AppDatabase::class.java, "court-assistant-db"
        ).build()

        // Initialize DAOs
        Daos.initialize(
            smsDao = database.smsDao(),
            documentDao = database.documentDao(),
            summonsDao = database.summonsDao(),
            calendarSyncDao = database.calendarSyncDao()
        )

        // Initialize repositories
        RepositoryManager.initialize(
            smsDao = Daos.smsDao,
            documentDao = Daos.documentDao,
            summonsDao = Daos.summonsDao,
            calendarSyncDao = Daos.calendarSyncDao
        )
    }
}
```

## Best Practices

1. **Always use Result type** - Never return raw data from repositories
2. **Handle errors properly** - Check for Result.Error cases
3. **Use Flow for real-time updates** - Use Flow-based methods for live data
4. **Keep repositories lean** - Repository should only contain data access logic
5. **Use mappers for conversion** - Keep entity and domain models separate

## Error Handling

```kotlin
// Error handling example
fun handleError(result: Result<*>) {
    when (result) {
        is Result.Success -> {
            // Success case
        }
        is Result.Error -> {
            val errorMessage = result.message
            val throwable = result.throwable

            // Show error to user or log it
            when (throwable) {
                is SQLiteException -> {
                    // Database specific error
                }
                is IOException -> {
                    // Network error
                }
                else -> {
                    // Generic error
                }
            }
        }
        Result.Loading -> {
            // Show loading indicator
        }
    }
}
```

## Migration from Old Code

Old code that used direct DAO access:
```kotlin
// Old way
val smsList = Daos.smsDao.getAllSync()
```

New code using Repository Pattern:
```kotlin
// New way
val result = RepositoryManager.smsRepository.getAllSync()
result.handle(
    onSuccess = { smsList ->
        // Use smsList
    },
    onError = { error ->
        // Handle error
    }
)
```

## Testing

Repositories can be easily mocked for testing:
```kotlin
@Test
fun testSmsRepository() {
    // Create mock repository
    val mockRepository = MockSmsRepository()

    // Test methods
    val result = mockRepository.getAll()
    assertTrue(result.isSuccess)
}
```
